features AS (
  SELECT
    item->>'pcode' AS pcode,
    item->'geometry' AS geometry,
    NULLIF(item->>'source_fid', '')::integer AS source_fid,
    NULLIF(item->>'source_date', '')::date AS source_date,
    NULLIF(item->>'source_valid_on', '')::date AS source_valid_on,
    NULLIF(item->>'source_valid_to', '')::date AS source_valid_to,
    NULLIF(item->>'source_area_sqkm', '')::numeric AS source_area_sqkm
  FROM payload
),
updated AS (
  UPDATE public.city_barangays cb
  SET
    geometry = public.normalize_geojson_multipolygon(f.geometry),
    source_fid = f.source_fid,
    source_date = f.source_date,
    source_valid_on = f.source_valid_on,
    source_valid_to = f.source_valid_to,
    source_area_sqkm = f.source_area_sqkm,
    updated_at = timezone('utc', now())
  FROM features f
  WHERE cb.pcode = f.pcode
  RETURNING cb.id, cb.pcode
)
SELECT
  (SELECT count(*) FROM features) AS features_loaded,
  (SELECT count(*) FROM updated) AS rows_updated,
  (SELECT count(*) FROM public.city_barangays WHERE geometry IS NULL) AS remaining_geometry_null;

COMMIT;
